def max_subtree_difference(n: int, colors: list, edges: list) -> list:
    # Convert colors to contribution values (1 for white, -1 for black)
    st = [2*x-1 for x in colors] + [0]

    # Create adjacency list representation of the tree
    g = [[] for _ in range(n)]
    for u, v in edges:
        g[u-1].append(v-1)
        g[v-1].append(u-1)

    # Find parent for each node using BFS
    p = [-1] * n
    q = [0]  # Start from node 0
    while q:
        v = q.pop()
        for x in g[v]:
            if x == p[v]:
                continue
            p[x] = v
            q.append(x)

    # First DFS: compute subtree contribution bottom-up
    seen = [0] * n
    q = [0]
    while q:
        v = q[-1]
        if seen[v]:
            q.pop()
            if st[v] > 0:
                st[p[v]] += st[v]
        else:
            for x in g[v]:
                if x == p[v]:
                    continue
                q.append(x)
            seen[v] = 1

    # Second DFS: propagate contributions from parent to children
    seen = [0] * n
    q = [0]
    while q:
        v = q.pop()
        for x in g[v]:
            if x == p[v]:
                continue
            c = st[v]
            if st[x] > 0:
                c -= st[x]
            if c > 0:
                st[x] += c
            q.append(x)

    return st[:n]

def min_total_votes(N: int, votes_ratio: list) -> int:
    def ceil(a, b):
        return -(-a // b)

    scr_t, scr_a = 0, 0
    for t, a in votes_ratio:
        if t >= scr_t and a >= scr_a:
            scr_t = t
            scr_a = a
        elif t < scr_t and a >= scr_a:
            scr_t = t * ceil(scr_t, t)
            scr_a = scr_t * a // t
        elif a < scr_a and t >= scr_t:
            scr_a = a * ceil(scr_a, a)
            scr_t = scr_a * t // a
        else:
            if t / a >= scr_t / scr_a:
                scr_a = a * ceil(scr_a, a)
                scr_t = scr_a * t // a
            else:
                scr_t = t * ceil(scr_t, t)
                scr_a = scr_t * a // t

    return scr_t + scr_a

