def restore_permutation(n: int, q: list) -> list:
    # Convert differences to prefix sums to get potential permutation
    prefix_sums = [0]
    for diff in q:
        prefix_sums.append(prefix_sums[-1] + diff)

    # Shift the values to make the minimum value 1
    min_value = min(prefix_sums)
    potential_perm = [x - min_value + 1 for x in prefix_sums]

    # Check if it's a valid permutation (contains each number from 1 to n exactly once)
    if set(potential_perm) == set(range(1, n + 1)):
        return potential_perm
    else:
        return [-1]

