def min_edges_for_shortest_path(n: int, edges: list) -> int:
    # Build adjacency list
    g = {}
    for u, v in edges:
        u -= 1  # Convert to 0-indexed
        v -= 1
        g.setdefault(u, []).append(v)
        g.setdefault(v, []).append(u)

    # BFS to find the shortest path and ranks
    st = [0]  # Start from vertex 1 (0-indexed)
    rank = [0] * n
    tree = [0] * n
    msk = [0] * n
    rd = {}

    while len(st) > 0:
        top = st.pop()
        msk[top] = 1
        for c in g.get(top, []):
            if msk[c] == 0:
                st.append(c)
                tree[c] = top
                rank[c] = rank[top] + 1
                rd.setdefault(rank[c], []).append(c)

    max_rank = max(rank)
    reach = [0] * n
    build = [0] * n

    for r in range(max_rank, 2, -1):
        for node in rd.get(r, []):
            if reach[node] == 0:
                reach[node] = 1
                reach[tree[node]] = 1
                reach[tree[tree[node]]] = 1
                build[tree[node]] = 1

    return sum(build)

def min_changes_to_make_arithmetic_progression(b: list) -> int:
    n = len(b)
    if n == 1:
        return 0

    min_changes = n + 1  # Set to a value larger than possible changes

    # Try all possible combinations of adjustments for the first two elements
    for a in range(-1, 2):
        for b_adj in range(-1, 2):
            valid = True
            total_changes = 0

            # Count changes for first two elements
            if a != 0:
                total_changes += 1
            if b_adj != 0:
                total_changes += 1

            # Calculate the common difference based on adjusted first two elements
            first_elem = b[0] + a
            second_elem = b[1] + b_adj
            diff = second_elem - first_elem

            # Check if the rest of the sequence can be adjusted to match the progression
            current_elem = second_elem
            for j in range(2, n):
                next_elem = current_elem + diff
                if abs(b[j] - next_elem) <= 1:  # Can adjust by at most 1
                    if b[j] != next_elem:
                        total_changes += 1
                    current_elem = next_elem
                else:
                    valid = False
                    break

            if valid:
                min_changes = min(min_changes, total_changes)

    if min_changes <= n:
        return min_changes
    else:
        return -1

