def count_vertex_pairs_with_weight_constraint(n, edges, queries):
    maxN = 2 * (10 ** 5) + 10
    edge_by_weight = [[] for i in range(maxN)]
    query_by_weight = [[] for _ in range(maxN)]
    ans = [0] * len(queries)
    sz = [1 for _ in range(n)]
    p = [i for i in range(n)]
    total_sum = 0

    def get(u):
        if p[u] == u:
            return u
        p[u] = get(p[u])
        return p[u]

    def unite(u, v):
        u = get(u)
        v = get(v)
        if u == v:
            return
        nonlocal total_sum
        total_sum -= (sz[u] * (sz[u] - 1)) // 2
        total_sum -= (sz[v] * (sz[v] - 1)) // 2
        total_sum += ((sz[u] + sz[v]) * (sz[u] + sz[v] - 1)) // 2
        if sz[u] < sz[v]:
            p[u] = v
            sz[v] += sz[u]
        else:
            p[v] = u
            sz[u] += sz[v]

    for u, v, w in edges:
        u -= 1  # Convert to 0-indexed
        v -= 1
        edge_by_weight[w].append((u, v))

    for i, q in enumerate(queries):
        query_by_weight[q].append(i)

    for i in range(maxN):
        for u, v in edge_by_weight[i]:
            unite(u, v)
        for idx in query_by_weight[i]:
            ans[idx] = total_sum

    return ans

