def count_divisors_factorial_mod(N: int) -> int:
    mod = 1000000007
    from collections import Counter
    Y = Counter()
    for i in range(2, N+1):
        M = i
        for j in range(2, i+1):
            while M % j == 0:
                Y[j] += 1
                M //= j

    result = 1
    for count in Y.values():
        result *= (count + 1)
        result %= mod

    return result

