        return math.sqrt((town1[0] - town2[0])**2 + (town1[1] - town2[1])**2)

    total_length = 0
    all_permutations = list(itertools.permutations(range(n)))

    for perm in all_permutations:
        path_length = 0
        for i in range(n-1):
            path_length += distance(towns[perm[i]], towns[perm[i+1]])
        total_length += path_length

    return total_length / len(all_permutations)

