def find_smallest_integer(N: int, M: int, constraints: list) -> int:
    # Create a dictionary to store constraints
    digit_constraints = {}

    # Process constraints
    for s, c in constraints:
        # If position already has a different constraint, return -1
        if s in digit_constraints and digit_constraints[s] != c:
            return -1
        digit_constraints[s] = c

    # Check if first digit is constrained to be 0 and N > 1
    if 1 in digit_constraints and digit_constraints[1] == 0 and N > 1:
        return -1

    # Start with the smallest possible number of N digits
    if N == 1:
        result = 0
    else:
        result = 10 ** (N - 1)

    # Convert to string for digit manipulation
    result_str = str(result)

    # Adjust digits based on constraints
    for position in range(1, N + 1):
        if position in digit_constraints:
            target_digit = digit_constraints[position]
            current_digit = int(result_str[position - 1])

            if target_digit < current_digit:
                # If target is less than current, we need to increase a more significant digit
                # This is only a problem for the first digit when N > 1
                if position == 1 and N > 1 and target_digit == 0:
                    return -1

                # Reconstruct number with the new digit
                result_str = result_str[:position - 1] + str(target_digit) + '0' * (N - position)
                result = int(result_str)

            elif target_digit > current_digit:
                # If target is greater than current, we set this digit and reset following digits
                result_str = result_str[:position - 1] + str(target_digit) + '0' * (N - position)
                result = int(result_str)

    # Final verification
    result_str = str(result)
    if len(result_str) != N:
        return -1

    for s, c in constraints:
        if int(result_str[s - 1]) != c:
            return -1

    return result

