def calculate_win_probability(n: int, k: int) -> float:
    ans = 0

    for i in range(1, n+1):
        if i >= k:
            ans += (1/n)
            continue
        x = 1
        temp_i = i
        while True:
            temp_i *= 2
            if temp_i >= k:
                break
            else:
                x += 1
        ans += (1/n) * (1/2)**x

    return ans

def earliest_arrival_time(n: int, trains_info: list) -> list:
    result = [0] * n

    # For each starting station
    for i in range(n-1):
        time = 0

        # Travel from station i to N
        for j in range(i, n-1):
            c_j, s_j, f_j = trains_info[j]

            # If we arrive before the first train
            if time <= s_j:
                time = s_j + c_j
            else:
                # If we arrive exactly when a train departs
                if (time - s_j) % f_j == 0:
                    time = time + c_j
                else:
                    # Wait for the next train
                    wait_time = f_j - ((time - s_j) % f_j)
                    time = time + wait_time + c_j

        result[i] = time

    return result

